// /frontend/src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

// Note: RainViewer public API for frames. If your backend proxies this, point there.
const METADATA_URL = "https://api.rainviewer.com/public/weather-maps.json";

// palette logic: radar tiles carry intensity; we show a legend & let the tile colors through.
// Additionally, we load a "snow" mask layer and tint it blue, while keeping high dbZ visually strong.
export default function Radar() {
  const mapRef = useRef(null);
  const [frames, setFrames] = useState({ past: [], nowcast: [], host: "" });
  const [index, setIndex] = useState(0);
  const [mode, setMode] = useState("radar"); // "radar" | "snow"

  useEffect(() => {
    let active = true;
    (async () => {
      try {
        const r = await fetch(METADATA_URL).then((r) => r.json());
        if (!active) return;
        const all = [...(r?.radar?.past ?? []), ...(r?.radar?.nowcast ?? [])];
        setFrames({ past: all, nowcast: [], host: r?.host || "" });
      } catch (e) {
        console.error("RainViewer metadata failed", e);
      }
    })();
    return () => {
      active = false;
    };
  }, []);

  useEffect(() => {
    if (mapRef.current) return;
    const map = L.map("radar-map", {
      zoomSnap: 0.5,
      zoomControl: false,
      attributionControl: false,
      preferCanvas: true,
    }).setView([33.749, -84.388], 6); // center on ATL by default; change if you want

    // Base dark map
    L.tileLayer(
      "https://{s}.tile.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",
      { subdomains: "abcd", maxZoom: 18, opacity: 0.9 }
    ).addTo(map);

    mapRef.current = map;
  }, []);

  // build tile urls and animate
  useEffect(() => {
    const map = mapRef.current;
    if (!map || !frames.host || frames.past.length === 0) return;

    let radarLayer = null;
    const addFrame = (i) => {
      const ts = frames.past[i]?.time;
      if (!ts) return;
      const layerPath =
        mode === "snow"
          ? `${frames.host}/v2/snow/${ts}/256/{z}/{x}/{y}.png` // snow mask
          : `${frames.host}/v2/radar/${ts}/256/{z}/{x}/{y}.png`;

      const opacity = mode === "snow" ? 0.9 : 0.8;
      if (radarLayer) map.removeLayer(radarLayer);
      radarLayer = L.tileLayer(layerPath, { opacity, zIndex: 500 }).addTo(map);

      // Optional: tint snow blue via CSS filter on the tile panes (simple, not perfect)
      const pane = radarLayer.getContainer();
      if (pane) {
        pane.style.filter = mode === "snow" ? "hue-rotate(180deg) saturate(1.2)" : "none";
      }
    };

    addFrame(index);

    // auto-play
    const id = setInterval(() => {
      const next = (index + 1) % frames.past.length;
      addFrame(next);
      setIndex(next);
    }, 1000);

    return () => clearInterval(id);
  }, [frames, index, mode]);

  const legend = useMemo(
    () => (
      <div className="absolute bottom-3 left-3 text-xs rounded-lg bg-black/60 px-2 py-1 ring-1 ring-white/10">
        <div className="font-medium mb-1">Precip Intensity</div>
        <div className="flex items-center gap-2">
          <span className="inline-block h-2 w-6 bg-blue-400" /> Snow (blue)
          <span className="inline-block h-2 w-6 bg-yellow-400" /> Moderate
          <span className="inline-block h-2 w-6 bg-red-500" /> Heavy (red)
        </div>
      </div>
    ),
    []
  );

  return (
    <div className="relative rounded-2xl overflow-hidden backdrop-blur-xl bg-black/40 ring-1 ring-white/10">
      <div className="flex items-center justify-between px-3 py-2">
        <div className="text-sm opacity-80">Radar</div>
        <div className="flex gap-2">
          <button
            className={`text-xs px-2 py-1 rounded ${mode === "radar" ? "bg-white/20" : "bg-white/10"}`}
            onClick={() => setMode("radar")}
          >
            Rain/Storm
          </button>
          <button
            className={`text-xs px-2 py-1 rounded ${mode === "snow" ? "bg-white/20" : "bg-white/10"}`}
            onClick={() => setMode("snow")}
          >
            Snow
          </button>
        </div>
      </div>

      <div id="radar-map" style={{ height: 320, width: "100%" }} />

      {legend}
    </div>
  );
}
